pipeline.evaluate:
(() => {
  const routerData = window._ROUTER_DATA?.loaderData?.chat_layout;
  const isLogin = typeof routerData?.userSetting?.data?.is_login === 'boolean' ? routerData.userSetting.data.is_login : null;
  const loggedIn = isLogin === null ? 'Unknown' : isLogin ? 'Yes' : 'No';
  const status = isLogin === false ? 'Login Required' : 'Connected';
  return [{ Status: status, Login: loggedIn, Url: window.location.href, Title: document.title || 'Doubao' }];
})()
